#!/usr/bin/env python3
"""
Bug #2576: jax.jit (XLA) produces wrong output vs PyTorch eager reference.

Patterns    : [['branch', 'triple_add_residual'], ['fusion', 'matmul_bias_relu'], ['constant', 'mul_zero_elim'], ['constant', 'where_const_condition'], ['normalization', 'layernorm_relu'], ['fusion', 'relu_add_relu']]
Dependencies: numpy jax
Run         : python unique_2576.py  →  exit 0 = BUG REPRODUCED
"""
import sys
import numpy as np
import jax, jax.numpy as jnp
from jax import lax
import jax.scipy.special

# ── Model weights ─────────────────────────────────────────────────────────────
_w0 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([256, 512])
_w1 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([512])
_w2 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 512])
_w3 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 512])
_w4 = np.frombuffer(bytes.fromhex(""), dtype=np.int64).reshape([1, 512])
_w5 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 512])
_w6 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([512])
_w7 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([512])

# ── Triggering input ─────────────────────────────────────────────────────────
INPUT = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 256])  # input "model_input"

EXPECTED = np.frombuffer(bytes.fromhex(""), dtype=np.float32)  # pytorch_eager reference


# ── Model computation (translated from ONNX) ──────────────────────────────────
def model(x):
    n0_tad_a1 = x + x
    n0_tad_a2 = n0_tad_a1 + x
    n0_tad_out = n0_tad_a2 + x
    n100_mmbrelu_mm = jnp.matmul(n0_tad_out, _w0)
    n100_mmbrelu_add = n100_mmbrelu_mm + _w1
    n100_mmbrelu_out = jnp.maximum(n100_mmbrelu_add, np.float32(0.0))
    n200_mze_mz = n100_mmbrelu_out * _w2
    n200_mze_out = n200_mze_mz + _w3
    n300_wcc_wh = jnp.where(_w4, n200_mze_out, _w5)
    n300_wcc_out = n300_wcc_wh * n200_mze_out
    n400_lnr_ln = (((lambda _x: (lambda _m, _v: (_x - _m) / jnp.sqrt(_v + np.float32(9.999999747378752e-06)))(jnp.mean(_x, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True), jnp.mean((_x - jnp.mean(_x, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True))**2, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True)))(n300_wcc_out)) * _w6) + _w7
    n400_lnr_out = jnp.maximum(n400_lnr_ln, np.float32(0.0))
    n500_rar_r1 = jnp.maximum(n400_lnr_out, np.float32(0.0))
    n500_rar_ad = n500_rar_r1 + n400_lnr_out
    n500_rar_out = jnp.maximum(n500_rar_ad, np.float32(0.0))
    return jnp.asarray(n500_rar_out, dtype=jnp.float32)


if __name__ == "__main__":
    x_jax = jnp.array(INPUT)
    out = np.array(jax.jit(model)(x_jax), dtype=np.float32).ravel()

    diff = float(np.linalg.norm(EXPECTED.astype(np.float64) - out.astype(np.float64))
                 / (np.linalg.norm(EXPECTED.astype(np.float64)) + 1e-8))
    print(f"expected (pytorch_eager): {EXPECTED[:6]}")
    print(f"actual   (jax.jit/XLA) : {out[:6]}")
    print(f"rel L2 : {diff:.4e}")
    if diff > 0.001:
        print("BUG REPRODUCED")
        sys.exit(0)
    sys.exit(1)
